

const URL_API = 'https://api.openagenda.com/v2/agendas/2119473/events?key=44b8dba66eef406c8dded12b7d7b01d5';

let evenements = [];
let categorie = 'tous';
let recherche = '';
let page = 1;
const PAR_PAGE = 6;

const liste = document.getElementById('liste');
const pagination = document.getElementById('pagination');
const champRecherche = document.getElementById('recherche');
const boutons = document.querySelectorAll('.boutons-filtres button');
const annonce = document.getElementById('annonce');


// chargement
async function charger() {
    try {
        const reponse = await fetch(URL_API);
        const donnees = await reponse.json();
        evenements = donnees.events;
        if (!evenements || evenements.length === 0) {
            evenements = donneesMarseille();
        }
        afficher();
    } catch (erreur) {
        evenements = donneesMarseille();
        afficher();
    }
}


// afficher
function afficher() {
    const resultats = evenements.filter(e => {
        const cat = obtenirCategorie(e).toLowerCase();
        const titre = obtenirTexte(e.title).toLowerCase();
        const okCategorie = categorie === 'tous' || cat.includes(categorie.toLowerCase());
        const okRecherche = recherche === '' || titre.includes(recherche.toLowerCase());
        return okCategorie && okRecherche;
    });

    liste.innerHTML = '';
    pagination.innerHTML = '';

    if (resultats.length === 0) {
        const message = document.createElement('p');
        message.textContent = 'Aucun événement trouvé.';
        liste.appendChild(message);
        annonce.textContent = 'Aucun événement trouvé';
        return;
    }

    const debut = (page - 1) * PAR_PAGE;
    const fin = debut + PAR_PAGE;
    resultats.slice(debut, fin).forEach(e => liste.appendChild(creerCarte(e)));

    creerPagination(resultats.length);
    annonce.textContent = resultats.length + ' événements affichés, page ' + page;
}


// creation carte
function creerCarte(e) {
    const titre = obtenirTexte(e.title);
    const cat = obtenirCategorie(e);
    const lieu = e.location?.name || 'Marseille';
    const date = formaterDate(e.timings?.[0]?.begin);

    // Image : reconstituer l'URL complète (base = préfixe CDN, filename = nom du fichier)
    const imageUrl = (e.image?.base && e.image?.filename)
        ? e.image.base + e.image.filename
        : null;

    const carte = document.createElement('article');
    carte.className = 'carte';
    carte.setAttribute('role', 'link');
    carte.setAttribute('tabindex', '0');
    carte.setAttribute('aria-label', titre + ' - ' + date + ' - ' + lieu);

    // Image avec fallback robuste
    const picture = document.createElement('picture');
    const img = document.createElement('img');
    img.alt = titre;
    img.setAttribute('loading', 'lazy');
    img.width = 400;
    img.height = 180;

    if (imageUrl) {
        img.src = imageUrl;
        img.onerror = function() {
            this.onerror = null;
            this.src = 'https://picsum.photos/seed/' + encodeURIComponent(titre) + '/400/180';
        };
    } else {
        img.src = 'https://picsum.photos/seed/' + encodeURIComponent(titre) + '/400/180';
    }

    picture.appendChild(img);
    carte.appendChild(picture);

    const infos = document.createElement('div');
    infos.className = 'infos';

    const spanCat = document.createElement('span');
    spanCat.className = 'categorie';
    spanCat.textContent = cat;
    infos.appendChild(spanCat);

    const h3 = document.createElement('h3');
    h3.textContent = titre;
    infos.appendChild(h3);

    const pDate = document.createElement('p');
    pDate.textContent = '📅 ' + date;
    infos.appendChild(pDate);

    const pLieu = document.createElement('p');
    pLieu.textContent = '📍 ' + lieu;
    infos.appendChild(pLieu);

    carte.appendChild(infos);

    carte.addEventListener('click', () => {
        sessionStorage.setItem('evenement', JSON.stringify(e));
        window.location.href = 'event-detail.html?id=' + e.uid;
    });

    carte.addEventListener('keydown', (ev) => {
        if (ev.key === 'Enter') {
            sessionStorage.setItem('evenement', JSON.stringify(e));
            window.location.href = 'event-detail.html?id=' + e.uid;
        }
    });

    return carte;
}


function creerPagination(total) {
    const totalPages = Math.ceil(total / PAR_PAGE);
    if (totalPages <= 1) return;

    const btnPrec = document.createElement('button');
    btnPrec.textContent = '←';
    btnPrec.setAttribute('aria-label', 'Page précédente');
    btnPrec.disabled = page === 1;
    btnPrec.addEventListener('click', () => { page--; afficher(); window.scrollTo({ top: 0, behavior: 'smooth' }); });
    pagination.appendChild(btnPrec);

    for (let i = 1; i <= totalPages; i++) {
        const btn = document.createElement('button');
        btn.textContent = i;
        btn.setAttribute('aria-label', 'Page ' + i);
        if (i === page) { btn.classList.add('actif'); btn.setAttribute('aria-current', 'page'); }
        btn.addEventListener('click', () => { page = i; afficher(); window.scrollTo({ top: 0, behavior: 'smooth' }); });
        pagination.appendChild(btn);
    }

    const btnSuiv = document.createElement('button');
    btnSuiv.textContent = '→';
    btnSuiv.setAttribute('aria-label', 'Page suivante');
    btnSuiv.disabled = page === totalPages;
    btnSuiv.addEventListener('click', () => { page++; afficher(); window.scrollTo({ top: 0, behavior: 'smooth' }); });
    pagination.appendChild(btnSuiv);
}



function obtenirTexte(champ) {
    if (!champ) return '';
    if (typeof champ === 'string') return champ;
    return champ.fr || '';
}

function obtenirCategorie(e) {
    return e.keywords?.fr?.[0] || 'Événement';
}

function formaterDate(date) {
    if (!date) return 'À venir';
    return new Date(date).toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' });
}



champRecherche.addEventListener('input', () => {
    recherche = champRecherche.value;
    page = 1;
    afficher();
});

boutons.forEach(b => {
    b.addEventListener('click', () => {
        boutons.forEach(x => { x.classList.remove('actif'); x.setAttribute('aria-pressed', 'false'); });
        b.classList.add('actif');
        b.setAttribute('aria-pressed', 'true');
        categorie = b.dataset.categorie;
        page = 1;
        afficher();
    });
});


